### Handle Image Upload and Display (JavaScript)

Source: https://github.com/huggingface/transformers.js/blob/main/docs/source/tutorials/vanilla-js.md

Adds an event listener to a file upload element to handle image selection. When a file is chosen, it uses `FileReader` to read the image data and displays it as an `<img>` element within a container. It also includes a commented-out placeholder for a detection function.

```javascript
fileUpload.addEventListener("change", function (e) {
  const file = e.target.files[0];
  if (!file) {
    return;
  }

  const reader = new FileReader();

  // Set up a callback when the file is loaded
  reader.onload = function (e2) {
    imageContainer.innerHTML = "";
    const image = document.createElement("img");
    image.src = e2.target.result;
    imageContainer.appendChild(image);
    // detect(image); // Uncomment this line to run the model
  };
  reader.readAsDataURL(file);
});
```

